import React, { useState, useEffect } from 'react';
import {
  Box,
  Card,
  CardContent,
  Grid,
  TextField,
  Button,
  FormControlLabel,
  Switch,
  Typography,
  Select,
  MenuItem,
  FormControl,
  InputLabel,
  Alert,
  Snackbar,
  Stack,
  IconButton,
  Tooltip
} from '@mui/material';
import { getSettings, updateSettings } from '../services/api';
import { Info as InfoIcon } from '@mui/icons-material';

const Settings = () => {
  const [settings, setSettings] = useState({
    network: {
      theme: 'auto',
      password: '',
      confirmPassword: '',
      port: 2345
    },
    dns: {
      mainIP: '10.0.0.1',
      dnsType: 'IPV4',
      usePTConnection: false
    },
    proxy: {
      proxyName: 'Proxy',
      yacdPassword: ''
    }
  });

  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [success, setSuccess] = useState(false);

  useEffect(() => {
    fetchSettings();
  }, []);

  const fetchSettings = async () => {
    try {
      setLoading(true);
      const data = await getSettings();
      setSettings(data);
    } catch (err) {
      setError('Failed to load settings');
    } finally {
      setLoading(false);
    }
  };

  const handleChange = (section, field) => (event) => {
    setSettings(prev => ({
      ...prev,
      [section]: {
        ...prev[section],
        [field]: event.target.type === 'checkbox' ? event.target.checked : event.target.value
      }
    }));
  };

  const handleSubmit = async (section) => {
    try {
      setLoading(true);
      await updateSettings({ [section]: settings[section] });
      setSuccess(true);
    } catch (err) {
      setError('Failed to update settings');
    } finally {
      setLoading(false);
    }
  };

  const handleOpenYacd = () => {
    window.open('/ui/yacd/', '_blank');
  };

  return (
    <Box>
      <Snackbar 
        open={success} 
        autoHideDuration={3000} 
        onClose={() => setSuccess(false)}
      >
        <Alert severity="success">设置已保存</Alert>
      </Snackbar>

      <Snackbar 
        open={!!error} 
        autoHideDuration={3000} 
        onClose={() => setError(null)}
      >
        <Alert severity="error">{error}</Alert>
      </Snackbar>

      <Typography variant="h5" gutterBottom>设置</Typography>

      <Grid container spacing={2}>
        {/* Network Settings */}
        <Grid item xs={12} md={6}>
          <Card>
            <CardContent>
              <Typography variant="h6" gutterBottom>网络设置</Typography>
              <Stack spacing={2}>
                <FormControl fullWidth size="small">
                  <InputLabel>主题</InputLabel>
                  <Select
                    value={settings.network.theme}
                    onChange={handleChange('network', 'theme')}
                    label="主题"
                  >
                    <MenuItem value="auto">自动</MenuItem>
                    <MenuItem value="light">亮色</MenuItem>
                    <MenuItem value="dark">暗色</MenuItem>
                  </Select>
                </FormControl>
                <TextField
                  fullWidth
                  size="small"
                  label="修改密码"
                  type="password"
                  value={settings.network.password}
                  onChange={handleChange('network', 'password')}
                />
                <TextField
                  fullWidth
                  size="small"
                  label="确认密码"
                  type="password"
                  value={settings.network.confirmPassword}
                  onChange={handleChange('network', 'confirmPassword')}
                />
                <Button 
                  variant="contained" 
                  onClick={() => handleSubmit('network')}
                  disabled={loading}
                  fullWidth
                >
                  保存
                </Button>
              </Stack>
            </CardContent>
          </Card>
        </Grid>

        {/* DNS Settings */}
        <Grid item xs={12} md={6}>
          <Card>
            <CardContent>
              <Box sx={{ display: 'flex', alignItems: 'center', mb: 2 }}>
                <Typography variant="h6">回源配置</Typography>
                <Tooltip title="ddns 域名/公网ip">
                  <IconButton size="small" sx={{ ml: 1 }}>
                    <InfoIcon fontSize="small" />
                  </IconButton>
                </Tooltip>
              </Box>
              <Stack spacing={2}>
                <TextField
                  fullWidth
                  size="small"
                  label="回源端口"
                  type="number"
                  value={settings.network.port}
                  onChange={handleChange('network', 'port')}
                />
                <TextField
                  fullWidth
                  size="small"
                  label="回源密码"
                  type="password"
                  value={settings.dns.password}
                  onChange={handleChange('dns', 'password')}
                />
                <FormControlLabel
                  control={
                    <Switch
                      checked={settings.dns.usePTConnection}
                      onChange={handleChange('dns', 'usePTConnection')}
                    />
                  }
                  label="启用"
                />
                <Button 
                  variant="contained" 
                  onClick={() => handleSubmit('dns')}
                  disabled={loading}
                  fullWidth
                >
                  保存
                </Button>
              </Stack>
            </CardContent>
          </Card>
        </Grid>

        {/* DNS Settings */}
        <Grid item xs={12} md={6}>
          <Card>
            <CardContent>
              <Typography variant="h6" gutterBottom>DNS设置</Typography>
              <Stack spacing={2}>
                <TextField
                  fullWidth
                  size="small"
                  label="主服IP"
                  value={settings.dns.mainIP}
                  onChange={handleChange('dns', 'mainIP')}
                />
                <FormControl fullWidth size="small">
                  <InputLabel>DNS类型</InputLabel>
                  <Select
                    value={settings.dns.dnsType}
                    onChange={handleChange('dns', 'dnsType')}
                    label="DNS类型"
                  >
                    <MenuItem value="IPV4">仅IPV4</MenuItem>
                    <MenuItem value="IPV6">仅IPV6</MenuItem>
                    <MenuItem value="BOTH">IPV4+IPV6</MenuItem>
                  </Select>
                </FormControl>
                <FormControlLabel
                  control={
                    <Switch
                      checked={settings.dns.usePTConnection}
                      onChange={handleChange('dns', 'usePTConnection')}
                    />
                  }
                  label="启用PT直连"
                />
                <Button 
                  variant="contained" 
                  onClick={() => handleSubmit('dns')}
                  disabled={loading}
                  fullWidth
                >
                  保存
                </Button>
              </Stack>
            </CardContent>
          </Card>
        </Grid>

        {/* YACD Settings */}
        <Grid item xs={12} md={6}>
          <Card>
            <CardContent>
              <Typography variant="h6" gutterBottom>其他配置</Typography>
              <Stack spacing={2}>
                <TextField
                  fullWidth
                  size="small"
                  label="通用规则名称"
                  value={settings.proxy.proxyName}
                  onChange={handleChange('proxy', 'proxyName')}
                />
                <TextField
                  fullWidth
                  size="small"
                  label="YACD 密码"
                  type="password"
                  value={settings.proxy.yacdPassword}
                  onChange={handleChange('proxy', 'yacdPassword')}
                />
                <Stack direction="row" spacing={1}>
                  <Button 
                    variant="contained" 
                    onClick={() => handleSubmit('proxy')}
                    disabled={loading}
                    fullWidth
                  >
                    保存
                  </Button>
                  <Button
                    variant="outlined"
                    onClick={handleOpenYacd}
                    fullWidth
                  >
                    打开YACD
                  </Button>
                </Stack>
              </Stack>
            </CardContent>
          </Card>
        </Grid>
      </Grid>
    </Box>
  );
};

export default Settings;
